import React from 'react';

function MovieDetails({ data, onClose }) {
    if (!data) return null;

    const castDetailed = data.cast_detailed || [];
    const rating = data.rating || 0;
    const voteCount = data.vote_count || 0;
    const title = data.title || data.name || "Untitled";
    const synopsis = data.synopsis || data.overview || `Details are not available for "${title}."`;

    const hasBackdrop = Boolean(data.backdrop);
    const hasPoster = Boolean(data.poster);

    const renderStars = (score) => {
        const stars5 = score / 2;
        const full = Math.floor(stars5);
        const half = stars5 - full >= 0.25;
        const empty = 5 - full - (half ? 1 : 0);
        return (
            <span className="stars-row">
                {'★'.repeat(full)}
                {half && <span className="star-half">★</span>}
                {'☆'.repeat(empty)}
            </span>
        );
    };

    return (
        <div className="movie-details-hero">
            <div className={hasBackdrop ? "hero-backdrop" : "hero-backdrop hero-backdrop-fallback"}>
                {hasBackdrop && <img src={data.backdrop} alt={title} />}
                <div className="hero-overlay" />
            </div>
            <button className="detail-close" onClick={onClose}>Close Details</button>
            <div className="hero-content hero-details-content">
                <div className="hero-layout">
                    <div className="hero-poster-wrap">
                        {hasPoster ? (
                            <img src={data.poster} alt={title} className="hero-poster" />
                        ) : (
                            <div className="hero-poster-fallback">{title.charAt(0)}</div>
                        )}
                    </div>

                    <div className="hero-info">
                        <h1 className="hero-title">{title}</h1>

                        {rating > 0 && (
                            <div className="hero-rating">
                                <span className="rating-score">{rating.toFixed(1)}</span>
                                <div className="rating-details">
                                    <div className="rating-stars">{renderStars(rating)}</div>
                                    {voteCount > 0 && (
                                        <span className="rating-votes">{voteCount.toLocaleString()} votes</span>
                                    )}
                                </div>
                            </div>
                        )}

                        <div className="hero-meta">
                            {data.year && data.year !== '—' && <span className="meta-tag">{data.year}</span>}
                            {data.genres && data.genres.map((g, i) => (
                                <span key={i} className="meta-tag">{g}</span>
                            ))}
                            {data.runtime && data.runtime !== '—' && <span className="meta-tag">{data.runtime}</span>}
                            {data.language && <span className="meta-tag">{data.language}</span>}
                        </div>

                        <div className="hero-section">
                            <h3 className="section-label">Synopsis</h3>
                            <p className="hero-synopsis">{synopsis}</p>
                        </div>

                        <div className="hero-credits-row">
                            {data.director && (
                                <div className="hero-credit">
                                    <span className="credit-label">Director</span>
                                    <span className="credit-value">{data.director}</span>
                                </div>
                            )}
                            {data.writer && (
                                <div className="hero-credit">
                                    <span className="credit-label">Writer</span>
                                    <span className="credit-value">{data.writer}</span>
                                </div>
                            )}
                        </div>

                        {data.quote && data.quote !== 'Every story has a beginning.' && (
                            <p className="hero-quote">"{data.quote}"</p>
                        )}
                    </div>
                </div>

                {castDetailed.length > 0 && (
                    <div className="cast-section">
                        <h3 className="section-label">Cast</h3>
                        <div className="cast-grid">
                            {castDetailed.map((member, i) => (
                                <div key={i} className="cast-card">
                                    <div className="cast-photo-wrap">
                                        {member.photo ? (
                                            <img
                                                src={member.photo}
                                                alt={member.name}
                                                className="cast-photo"
                                            />
                                        ) : (
                                            <div className="cast-photo-placeholder">
                                                {member.name.charAt(0)}
                                            </div>
                                        )}
                                    </div>
                                    <p className="cast-name">{member.name}</p>
                                    {member.character && (
                                        <p className="cast-character">{member.character}</p>
                                    )}
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {data.stills && data.stills.length > 0 && (
                    <div className="stills-section">
                        <h3 className="section-label">Gallery</h3>
                        <div className="stills-grid">
                            {data.stills.map((img, i) => (
                                <div key={i} className="still-card">
                                    <img src={img} alt={`Scene ${i + 1}`} />
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

export default MovieDetails;
